import json, sys
data = json.load(sys.stdin)
analyzers = data['Items']['Analyzer']
print(f'Total analyzer DLLs: {len(analyzers)}\n')
# Group by source
from collections import defaultdict
groups = defaultdict(list)
for a in analyzers:
    name = a['Filename']
    if 'Roslynator' in name: groups['Roslynator'].append(name)
    elif 'SonarAnalyzer' in name: groups['SonarAnalyzer'].append(name)
    elif 'Meziantou' in name: groups['Meziantou'].append(name)
    elif 'StyleCop' in name: groups['StyleCop'].append(name)
    elif 'CodeStyle' in name: groups['CodeStyle (EnforceCodeStyleInBuild)'].append(name)
    elif 'NetAnalyzers' in name: groups['NetAnalyzers (SDK built-in)'].append(name)
    else: groups['Other'].append(name)
for group, names in sorted(groups.items(), key=lambda x: -len(x[1])):
    print(f'{group}: {len(names)} DLLs')
"

